    34→export function TreeView({ areas, tests, onNewArea }: TreeViewProps) {
    35→  const [expandedAreas, setExpandedAreas] = useState<Set<string>>(new Set());
    36→
    37→  const toggleArea = (areaId: string) => {
    38→    const newExpanded = new Set(expandedAreas);
    39→    if (newExpanded.has(areaId)) {
    40→      newExpanded.delete(areaId);
    41→    } else {
    42→      newExpanded.add(areaId);
    43→    }
    44→    setExpandedAreas(newExpanded);
    45→  };
    46→
    47→  const testsByArea = tests.reduce((acc, test) => {
    48→    const areaId = test.functionalAreaId || 'uncategorized';
