    66→            return (
    67→              <div key={area.id} className="mb-1">
    68→                <button
    69→                  onClick={() => toggleArea(area.id)}
    70→                  className="flex items-center gap-2 w-full px-2 py-1.5 rounded hover:bg-muted text-sm"
