    75→                    <ChevronRight className="h-4 w-4" />
    76→                  )}
    77→                  <Folder className="h-4 w-4 text-primary" />
    78→                  <span className="flex-1 text-left">{area.name}</span>
    79→                  <span className="text-xs text-muted-foreground">
    80→                    {areaTests.length}
    81→                  </span>
    82→                </button>
    83→
    84→                {isExpanded && (
    85→                  <div className="ml-4 pl-2 border-l">
