   177→export function CompareClient({ branches, runs, defaultBaseline }: CompareClientProps) {
   178→  const [baseBranch, setBaseBranch] = useState<string>(defaultBaseline || '');
   179→  const [targetBranch, setTargetBranch] = useState<string>('');
   180→  const [baseInfo, setBaseInfo] = useState<BranchRunInfo | null>(null);
   181→  const [targetInfo, setTargetInfo] = useState<BranchRunInfo | null>(null);
   182→  const [isLoadingBase, setIsLoadingBase] = useState(false);
   183→  const [isLoadingTarget, setIsLoadingTarget] = useState(false);
   184→  const [queueStatus, setQueueStatus] = useState<{ queue: QueuedRun[]; activeRun: QueuedRun | null }>({
   185→    queue: [],
   186→    activeRun: null,
   187→  });
   188→
   189→  // Get runs grouped by branch for badge display
   190→  const runsByBranch = runs.reduce((acc, run) => {
   191→    if (!acc[run.gitBranch]) acc[run.gitBranch] = [];
   192→    acc[run.gitBranch].push(run);
   193→    return acc;
   194→  }, {} as Record<string, TestRun[]>);
   195→
   196→  // Fetch branch info when selection changes
   197→  const fetchBranchInfo = useCallback(async (branch: string, isBase: boolean) => {
   198→    if (!branch) return;
   199→
   200→    const setLoading = isBase ? setIsLoadingBase : setIsLoadingTarget;
   201→    const setInfo = isBase ? setBaseInfo : setTargetInfo;
   202→
   203→    setLoading(true);
   204→    try {
   205→      const info = await getLatestRunForBranch(branch);
   206→      setInfo(info);
   207→    } catch (error) {
   208→      console.error('Failed to fetch branch info:', error);
   209→      toast.error(`Failed to load ${branch} info`);
   210→    } finally {
   211→      setLoading(false);
   212→    }
   213→  }, []);
   214→
   215→  useEffect(() => {
   216→    if (baseBranch) {
   217→      fetchBranchInfo(baseBranch, true);
   218→    }
   219→  }, [baseBranch, fetchBranchInfo]);
   220→
   221→  useEffect(() => {
   222→    if (targetBranch) {
   223→      fetchBranchInfo(targetBranch, false);
   224→    }
   225→  }, [targetBranch, fetchBranchInfo]);
   226→
   227→  // Poll queue status when runs are active
   228→  useEffect(() => {
   229→    const pollQueue = async () => {
   230→      try {
   231→        const status = await getQueueStatus();
   232→        setQueueStatus(status);
   233→
   234→        // Refresh branch info when runs complete
   235→        const wasRunning = queueStatus.activeRun !== null;
   236→        const isNowIdle = status.activeRun === null && status.queue.length === 0;
   237→
   238→        if (wasRunning && isNowIdle) {
   239→          if (baseBranch) fetchBranchInfo(baseBranch, true);
   240→          if (targetBranch) fetchBranchInfo(targetBranch, false);
   241→          toast.success('Test run completed');
   242→        }
   243→      } catch (error) {
   244→        console.error('Failed to poll queue status:', error);
   245→      }
   246→    };
   247→
   248→    const interval = setInterval(pollQueue, 2000);
   249→    pollQueue();
   250→
   251→    return () => clearInterval(interval);
   252→  }, [baseBranch, targetBranch, fetchBranchInfo, queueStatus.activeRun]);
