   188→
   189→  // Get runs grouped by branch for badge display
   190→  const runsByBranch = runs.reduce((acc, run) => {
   191→    if (!acc[run.gitBranch]) acc[run.gitBranch] = [];
   192→    acc[run.gitBranch].push(run);
   193→    return acc;
   194→  }, {} as Record<string, TestRun[]>);
   195→
   196→  // Fetch branch info when selection changes
   197→  const fetchBranchInfo = useCallback(async (branch: string, isBase: boolean) => {
   198→    if (!branch) return;
   199→
   200→    const setLoading = isBase ? setIsLoadingBase : setIsLoadingTarget;
   201→    const setInfo = isBase ? setBaseInfo : setTargetInfo;
   202→
   203→    setLoading(true);
