   223→      fetchBranchInfo(targetBranch, false);
   224→    }
   225→  }, [targetBranch, fetchBranchInfo]);
   226→
   227→  // Poll queue status when runs are active
   228→  useEffect(() => {
   229→    const pollQueue = async () => {
   230→      try {
   231→        const status = await getQueueStatus();
